import { i18n } from '@fs/zion-locale'
import { useUser } from '@fs/zion-user'
import { geoData } from '@fs/zion-config'
import { buildLangUrl } from '@fs/zion-router'
import { useFeatureFlag } from '@fs/zion-flags'
import { usePermission } from '@fs/zion-permissions'
import { helpLinkBaseUrl } from './targetEnvFunctions'
import { helpRuLinkBaseUrl } from './targetRuEnvFunctions'

const supportedLanguages = ['de', 'en', 'es', 'fr', 'it', 'pt', 'ja', 'ko', 'zh']
const arabicCountryCodes = [
  'AE', // United Arab Emirates
  'BH', // Bahrain
  'DZ', // Algeria
  'EG', // Egypt
  'IL', // Israel
  'IQ', // Iraq
  'JO', // Jordan
  'KW', // Kuwait
  'LB', // Lebanon
  'LY', // Libya
  'MA', // Morocco
  'OM', // Oman
  'PS', // Palestine
  'QA', // Qatar
  'SA', // Saudi Arabia
  'SD', // Sudan
  'SY', // Syria
  'TN', // Tunisia
  'YE', // Yemen
]

const communitieslink = {
  fi: 'https://community.familysearch.org/en/group/266-familysearch-yhteisoe-suomi',
  ru: 'https://t.me/familysearch_rus',
  da: 'https://community.familysearch.org/en/group/296-familysearch-danmark',
  et: 'https://community.familysearch.org/en/group/329-eesti-uurimus-estonia',
  no: 'https://community.familysearch.org/en/group/299-familysearch-norge',
  sv: 'https://community.familysearch.org/en/group/271-familysearch-sverige',
}

export default function useFooterLinks() {
  const [authorized, requestStatus] = usePermission('CanAddPersonalDataPermission', 'FamilyTree')
  const { isOn: arabicContactUsFlagOn } = useFeatureFlag('home_footer_arabicContactUsLink')
  const { signedIn } = useUser()

  const canAddPersonalData = requestStatus === 'loaded' ? authorized : true
  const useRussianUrls = (signedIn && !canAddPersonalData) || i18n.language === 'ru'
  const useArabicUrls =
    arabicContactUsFlagOn && (arabicCountryCodes.includes(geoData?.country) || i18n.language === 'ar')
  const helpLinkUrl = useRussianUrls ? helpRuLinkBaseUrl : helpLinkBaseUrl

  // Help and Learning Link
  const helpAndLearningLink = buildLangUrl(`${helpLinkUrl}/help/helpcenter/landing`)

  // Communities Link
  let communitiesLink = 'https://community.familysearch.org/en/categories/other-languages'

  if (useRussianUrls) {
    communitiesLink = communitieslink.ru
  } else if (communitieslink[i18n.language]) {
    communitiesLink = communitieslink[i18n.language]
  } else if (supportedLanguages.includes(i18n.language) || !i18n.language) {
    communitiesLink = `${helpLinkUrl}/help/communities`
  }

  // Contact Us Link
  let contactUsLink = buildLangUrl(`${helpLinkUrl}/fieldops/familysearch-support-contact-us`)
  const finnishContactUsLink = `${helpLinkUrl}/fi/fieldops/eurooppa-ottaa-meihin-yhteytta`
  const arabicContactUsLink = `${helpLinkUrl}/ar/fieldops/middle-east-contact-us`

  if (i18n.language === 'fi') {
    contactUsLink = finnishContactUsLink
  } else if (useArabicUrls) {
    contactUsLink = arabicContactUsLink
  }

  // Helper Resources Link
  const helperResourcesLink = buildLangUrl(`${helpLinkUrl}/help/helper/`)

  return {
    helpAndLearningLink,
    communitiesLink,
    contactUsLink,
    helperResourcesLink,
  }
}
