import axios from '@fs/zion-axios'
import React, { useEffect, useState } from 'react'
import { colors } from '@fs/zion-ui'
import { buildLangUrl } from '@fs/zion-router'
import { helpLinkBaseUrl } from './targetEnvFunctions'

const hasDocument = typeof document !== 'undefined'

// Feel free to reach out to Ethan Stewart with questions, summary below
// We receive articles as an HTML string. We take the article content and the
// styles and put them inside the help overlay. Because of how we currently have
// to bring it in, the styles would be applied to the whole document. Using a
// custom element with shadow root allows us to scope it easily until we can work
// with Brightspot to see if there's a better way to do this
class ArticleContent extends HTMLElement {
  static get observedAttributes() {
    return ['content']
  }

  constructor() {
    super()
    this.attachShadow({ mode: 'open' })
  }

  attributeChangedCallback(name, oldVal, newVal) {
    if (name === 'content' && oldVal !== newVal) {
      this.shadowRoot.innerHTML = newVal
    }
  }
}
if (typeof window !== 'undefined' && typeof window.customElements.get('article-content') !== 'function') {
  window.customElements.define('article-content', ArticleContent)
}

// Used to display external HTML from another source
export default function HelpArticle({ Content }) {
  // This allows us to pass a component's function; main use case is passing
  // NoticeLoading to show a spinner while article is being fetched
  if (typeof Content === 'function') return <Content />
  // Otherwise render the content/styles with the custom element (see above
  // for an explanation on why we're doing it this way for now)
  return <article-content content={Content} />
}

// Hook that is used to get content based on a URL
// Updates when a new URL is set
export function useArticle(articleUrl) {
  const [articleHtml, setArticleHtml] = useState('')
  const [isLoading, setIsLoading] = useState(false)

  useEffect(() => {
    if (articleUrl) {
      const fullArticleUrl = articleUrl.startsWith('/') ? `${helpLinkBaseUrl}${articleUrl}` : articleUrl
      setIsLoading(true)
      axios
        .get(buildLangUrl(fullArticleUrl))
        .then((res) => {
          // Brightspot handler
          const html = extractBrightspotHtml(res.data)
          setArticleHtml(html)
        })
        .catch((err) => {
          console.error(err)
        })
        .then(() => {
          setIsLoading(false)
        })
    } else {
      setArticleHtml('')
    }
  }, [articleUrl])

  return { articleHtml, isLoading }
}

function extractBrightspotHtml(htmlString) {
  if (!hasDocument) {
    return ''
  }
  // Get the HTML from the url
  const div = document.createElement('div')
  div.innerHTML = htmlString

  // use dom query to get the article - fragile if url doesn't use <article>
  // API would be preferred
  const articleTitle = div.querySelector('.ArticlePage-headline')
  const articleHtml = div.querySelector('article')
  if (!articleHtml) return ''
  articleHtml.style.setProperty('--linkTextColor', colors.transparent.blue60)
  articleHtml.style.setProperty('--linkHoverColor', colors.transparent.blue80)
  articleHtml.querySelectorAll('a').forEach((link) => {
    link.target = '_blank'
  })

  // Remove Article Actions (print button)
  articleHtml.querySelector('div.ArticlePage-actions')?.remove()

  // Remove ThumbsModule (for now...)
  articleHtml.querySelector('div.ThumbsModule')?.remove()

  // add the styles of the article - potentially fragile, doesn't guarantee all styles
  // API would be preferred
  let html = articleHtml.outerHTML
  if (articleTitle) {
    html = articleTitle.outerHTML + articleHtml.outerHTML
  }
  const styles = div.querySelector('link[rel="stylesheet"]')
  if (styles) {
    return styles.outerHTML + html
  }
  // FIXME: Different fallback? Currently we're saying if there were no styles,
  // return nothing, even though we do have unstyled article content at this point
  return ''
}

export function isSupportedUrl(url) {
  return /\/help\/helpcenter\/(?:[a-z]{2,3}(?:-[a-z]{2,})*\/)?article/i.test(url)
}
