import { i18n } from '@fs/zion-locale'
import { useLocation } from '@fs/zion-router'
import { useEffect, useState } from 'react'
import { getTrayContent } from './HelpData'

export default function useSuggestedTopics({ overrideUrl, apiBaseUrl, isOpen }) {
  const [suggestedTopics, setSuggestedTopics] = useState([])
  const [error, setError] = useState(false)

  // Used to retrigger a component render, when user navigates
  const location = useLocation()

  useEffect(() => {
    /*
     * window.location.href: default, when no override is provided use the current page url to get content
     * overrideUrl: used to manually get content from Brightspot for a specific url
     * isOpen: only make backend call if the overlay is open
     */
    setError(false)

    // FIXME: Better handling/putting together of URL?
    const windowUrl = typeof window !== 'undefined' ? `${window?.location?.origin}${window?.location?.pathname}` : ''
    const url = typeof overrideUrl !== 'undefined' ? overrideUrl : windowUrl
    if (isOpen) {
      getTrayContent({ url, lang: i18n.language, apiBaseUrl })
        .then((content) => {
          setSuggestedTopics(content.items.filter((item) => item?.title?.length && item?.url?.length))
          setError(false)
        })
        .catch(() => {
          setError(true)
          setSuggestedTopics([])
        })
    }
  }, [location, overrideUrl, apiBaseUrl, isOpen])
  return { suggestedTopicsList: suggestedTopics, suggestedTopicsError: error }
}
