import React from 'react'
import { Link } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import { usePermission, useNonReligiousMode } from '@fs/zion-permissions'
import useFooterLinks from './useFooterLinks'

const overlayFooterLinksCss = css`
  display: flex;
  flex-wrap: wrap;
  padding: 0 8px;

  a {
    padding: 8px 0;
    &:not(:last-child) {
      margin-inline-end: 24px;
    }
  }
`

export default function HelpOverlayFooter() {
  const [t] = useTranslation()
  const [isMember] = usePermission('FtMemberUiPermission')
  const [nonReligiousModeCheck, status, error] = useNonReligiousMode()
  const isNonReligiousModeActive = status === 'loading' || error !== null || nonReligiousModeCheck
  const { helpAndLearningLink, communitiesLink, contactUsLink, helperResourcesLink } = useFooterLinks()

  return (
    <div className={overlayFooterLinksCss}>
      <Link
        to={helpAndLearningLink}
        data-test="helpOverlayHelpCenterLink"
        external
        wayfinding
        linkName="Help Overlay Help Center Link Clicked"
      >
        {t('help-tray.help-center.link', 'Help and Learning')}
      </Link>
      {!isNonReligiousModeActive && (
        <Link
          to={communitiesLink}
          data-test="helpOverlayCommunityLink"
          external
          wayfinding
          linkName="Help Overlay Communities Link Clicked"
        >
          {t('help-tray.community.link', 'Community')}
        </Link>
      )}
      <Link
        to={contactUsLink}
        data-test="helpOverlayContactUsLink"
        external
        wayfinding
        linkName="Help Overlay Contact Us Link Clicked"
      >
        {t('help-tray.contact-us.link', 'Contact Us')}
      </Link>
      {!isNonReligiousModeActive && (
        <Link
          to={helperResourcesLink}
          data-test="helpOverlayHelperResourcesLink"
          external
          wayfinding
          linkName="Help Overlay Helper Resources Link Clicked"
        >
          {isMember
            ? t('help-tray.helper-resources.link', 'Helper Resources')
            : t('help-tray.helpful-resources.link', 'Helpful Resources')}
        </Link>
      )}
    </div>
  )
}
