import { targetEnv } from '@fs/zion-config'

/**
 *
 * @param {string} target This is the target provided by build environments
 * @returns {Object} {apiBaseUrl: string - baseUrl to call Brightspot, helpLinkBaseUrl: string, baseUrl of /help}
 */
function getTargetUrls(target) {
  const currentTarget = target ?? window?.FS?.targetEnv ?? 'prod'

  // Api does not work in the Beta Domain
  const PROD = 'https://www.familysearch.org'
  const BETA = 'https://beta.familysearch.org'
  const INT = 'https://integration.familysearch.org'

  switch (currentTarget) {
    case 'local':
    case 'beta':
      return {
        apiBaseUrl: BETA,
        helpLinkBaseUrl: BETA,
      }
    case 'int':
      return {
        apiBaseUrl: BETA,
        helpLinkBaseUrl: INT,
      }
    case 'prod':
    default:
      return {
        apiBaseUrl: PROD,
        helpLinkBaseUrl: PROD,
      }
  }
}

const helpOverlayConfig = getTargetUrls(targetEnv)

export const { apiBaseUrl, helpLinkBaseUrl } = helpOverlayConfig
