import axios from '@fs/zion-axios'
import { i18n } from '@fs/zion-locale'
import { apiBaseUrl as fsBaseUrl } from './targetEnvFunctions'

// Api does not work in the Beta Domain
const BETA_DOMAIN = 'https://www.familysearch.org'
const BRIGHTSPOT_SITE = '/help/helpcenter/'
const BRIGHTSPOT_API = `/cmsa/api/v1`

export const DEFAULT_TRAY_CONTENT = {
  items: [],
  pageCount: 0,
  pageNumber: 0,
  total: 0,
}

export const DEFAULT_SEARCH_CONTENT = {
  results: [],
  pageCount: 0,
  pageNumber: 0,
  total: 0,
}

/**
 * @description call Brightspot to get Help Tray content
 * @param {string} url The options for url depend on what Help Overlay content
 * has been published in the CMS. You can see all published ones by logging in here
 * https://cms.prod.familysearch.psdops.com/cms/
 * @param {string} lang a language that FamilySearch supports
 * @returns {Promise}
 * {
 *  items: [
 *    {
 *      description: string,
 *      title: string,
 *      url: string
 *    }...
 *  ],
 *  pageCount: number,
 *  pageNumber: number,
 *  total: number
 *}
 */
export async function getTrayContent({ url: origUrl, lang, apiBaseUrl = '' }) {
  const url = fixPatronUrl(origUrl)
  try {
    const response = await axios.get(`${getApiUrl(apiBaseUrl, BRIGHTSPOT_API)}/helptray`, {
      params: {
        url,
        lang,
        site: `${getSiteDomain(url)}${BRIGHTSPOT_SITE}`,
      },
    })

    // Return the data ONLY IF content was recieved
    // It is possible to receive data, but no content prop
    if (response && typeof response.data !== 'undefined' && typeof response.data.content !== 'undefined') {
      return response.data.content
    }
  } catch (err) {
    if (err.response && err.response.message) {
      // When a provided URL does not have suggested topics, Brightspot returns a
      // 404 with a message of "No content associated". In order to distinguish this
      // from any other honest mistake leading to a 404, we have to check for that
      // message. If this is the case, just return the default response
      if (/No content associated/i.test(err.response.message)) {
        return DEFAULT_TRAY_CONTENT
      }
      // Throw an error if it's not something we recognize from Brightspot
      throw new Error('Failed to get content from Brightspot')
    }
    // If no response or message was provided, throw a generic error
    throw new Error('An unknown error occurred while fetching suggested topics')
  }

  return DEFAULT_TRAY_CONTENT
}

export async function getSearchResults({ queryString, lang, pageNumber, apiBaseUrl = '' }) {
  try {
    const response = await axios.get(`${getApiUrl(apiBaseUrl, BRIGHTSPOT_API)}/search`, {
      // Brightspot wants single character params...
      params: {
        q: queryString,
        lang,
        site: `${fsBaseUrl || BETA_DOMAIN}${BRIGHTSPOT_SITE}`,
        p: pageNumber,
      },
    })

    // Return the data ONLY IF content was recieved
    // It is possible to receive data, but no content prop
    if (response && typeof response.data !== 'undefined' && typeof response.data.content !== 'undefined') {
      return reformatSearchResponse(response).data.content
    }
  } catch (err) {
    // Handle errors?  or just revert to default content?
  }

  return DEFAULT_SEARCH_CONTENT
}

export async function getAutosuggestResults({ queryString, apiBaseUrl = '' }) {
  const results = await getSearchResults({ queryString, lang: i18n.language, pageNumber: 1, apiBaseUrl })

  if (Array.isArray(results.items)) {
    return results.items.map((item) => {
      return {
        primaryText: item.title,
        key: item.title,
        ...item,
      }
    })
  }

  return []
}

/**
 *
 * @param {object} response is the object returned directly from Brightspot
 * In order to share code with Suggested Topics we're changing
 * the property to items
 */
function reformatSearchResponse(response) {
  if (response.data.content.results) {
    response.data.content.items = response.data.content.results
    delete response.data.content.results
  }

  return response
}

/**
 * @description Modifies the users url to removing language codes (and handling localhost)
 * @param {string} url
 * @param {string} languageCode
 */
export function fixPatronUrl(url, languageCode = i18n.language) {
  try {
    const urlObj = new URL(url)
    if (urlObj.hostname === 'localhost') {
      urlObj.protocol = 'https:'
      urlObj.hostname = 'www.familysearch.org'
      urlObj.port = ''
    }
    /** This is removing the language code so Brightspot config can be language agnostic */
    urlObj.pathname = urlObj.pathname.replace(new RegExp(`^/${languageCode}`), '')
    /** Strip out parameters */
    urlObj.search = ''
    return urlObj.toString()
  } catch {
    return url
  }
}

// helps get the 'site' param
function getSiteDomain(url) {
  const urlObj = new URL(url)
  return urlObj.origin
}

// This function removes trailing slashes... and attaches the path
function getApiUrl(apiBaseUrl, apiPath) {
  const removeTrailingSlash = (origUrl) => origUrl.replace(/\/$/, '')
  return removeTrailingSlash(apiBaseUrl) + apiPath
}
