import { targetEnv } from '@fs/zion-config'

/**
 *
 * @param {string} target This is the target provided by build environments
 * @returns {Object} {apiBaseUrl: string - baseUrl to call Brightspot, helpLinkBaseUrl: string, baseUrl of /help}
 */
function getRuTargetUrls(target) {
  const currentTarget = target ?? window?.FS?.targetEnv ?? 'prod'

  // Api does not work in the Beta Domain
  const RU_PROD = 'https://www-ru.familysearch.org'
  const RU_BETA = 'https://beta-ru.familysearch.org'
  const RU_INT = 'https://integration-ru.familysearch.org'

  switch (currentTarget) {
    case 'local':
    case 'beta':
      return {
        helpRuLinkBaseUrl: RU_BETA,
      }
    case 'int':
      return {
        helpRuLinkBaseUrl: RU_INT,
      }
    case 'prod':
    default:
      return {
        helpRuLinkBaseUrl: RU_PROD,
      }
  }
}

const helpRuOverlayConfig = getRuTargetUrls(targetEnv)

export const { helpRuLinkBaseUrl } = helpRuOverlayConfig
