import React, { useCallback, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import { ListItem, colors } from '@fs/zion-ui'
import { Autosuggest, useAutosuggest } from '@fs/zion-ui-autosuggest'
import { MenuSearch, MenuNewWindow } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { css } from '@linaria/core'
import { getAutosuggestResults } from './HelpData'
import { helpLinkBaseUrl } from './targetEnvFunctions'
import { isSupportedUrl } from './HelpArticle'

const noMarginBottomCss = css`
  margin-top: 8px;
  margin-bottom: -16px;
`

const hasWindow = typeof window !== 'undefined'

export default function HelpOverlaySearch({ apiBaseUrlActual, loadArticle }) {
  const [t] = useTranslation()

  const getSuggestions = useCallback(
    async (queryString) => {
      if (!queryString.trim()) {
        return []
      }

      const results = await getAutosuggestResults({ queryString, apiBaseUrl: apiBaseUrlActual })
      const filteredResults = results.filter((result) => result.key !== undefined)

      const LAST_RESORT_TEXT = t('help-tray.see-all-results.action', 'See All Results')

      return {
        suggestions: filteredResults,
        lastResort: {
          primaryText: LAST_RESORT_TEXT,
          key: 'LAST_RESORT',
          startElement: queryString.length < 1 ? null : <ListItem.Icon Icon={MenuNewWindow} color={colors.blue50} />,
          onClick: () => {
            const searchThenCodeLanguages = new Set([
              'de',
              'es',
              'fr',
              'it',
              'pt',
              'ja',
              'ko',
              'zh',
              'ru', // end of core 10 languages (excluding 'en')
              'pl', // start of additional languages
              'sv',
            ])
            // Using helpLinkBaseUrl for the sake of pages like Community that aren't on the main FS URLs
            let helpCenterUrl = queryString
              ? `${helpLinkBaseUrl}/${i18n.language}/help/helpcenter/${i18n.language}/search?q=${queryString}`
              : `${helpLinkBaseUrl}/help/helpcenter`

            if (i18n.language === 'en') {
              helpCenterUrl = `${helpLinkBaseUrl}/${i18n.language}/help/helpcenter/search?q=${queryString}`
            }

            if (searchThenCodeLanguages.has(i18n.language)) {
              let searchLanguageCode = i18n.language
              if (i18n.language === 'pt') {
                searchLanguageCode = 'pr'
              }
              if (i18n.language === 'ja') {
                searchLanguageCode = 'jp'
              }
              helpCenterUrl = `${helpLinkBaseUrl}/${i18n.language}/help/helpcenter/search/${searchLanguageCode}?q=${queryString}`
            }

            hasWindow && window.open(helpCenterUrl, '_blank')
          },
        },
      }
    },
    [apiBaseUrlActual, t]
  )

  const handleSelection = useCallback((suggestion, userInput) => {
    if (suggestion?.url) {
      return suggestion.primaryText
    }
    return userInput // Keep user input if no suggestion selected
  }, [])

  const config = useAutosuggest({ handleSelection })

  const { selectedItem, set } = config

  // Handle actual selection when an item is selected (not just focused/previewed)
  // This effect fires when config.selectedItem changes due to actual selection
  useEffect(() => {
    if (selectedItem?.url) {
      if (isSupportedUrl(selectedItem.url)) {
        loadArticle(selectedItem.url)
      } else {
        hasWindow && window.open(selectedItem.url, '_blank')
      }
      // Clear the selectedItem and input after handling to allow normal typing
      set({ userInput: '', selectedItem: null })
    }
  }, [selectedItem, set, loadArticle])

  return (
    <div className={noMarginBottomCss}>
      <Autosuggest
        highlightMatchingText
        Icon={MenuSearch}
        placeholder={t('help-tray.search-field.placeholder', 'Search articles and lessons')}
        getSuggestions={getSuggestions}
        config={config}
        clearable
        debounce={750}
      />
    </div>
  )
}
