import React, { useContext, useEffect, useReducer, useState, lazy, Suspense } from 'react'
import PropTypes from 'prop-types'
import { css } from '@linaria/core'
import { HelpTutorialContext } from '@fs/zion-help-tutorial'
import { HelpCompass, HelpTip, MenuNewWindow, NoticeLoading } from '@fs/zion-icon'
import { Link } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { SupplementalOverlay } from '@fs/zion-ui/quarks-authorized-use-only'
import { colors, List, ListItem, Divider, Separator, Paragraph, H3 } from '@fs/zion-ui'

import Cache from '@fs/zion-cache'
import { usePermission } from '@fs/zion-permissions'
import { useUser } from '@fs/zion-user'
import HelpArticle, { isSupportedUrl, useArticle } from './HelpArticle'

import useSuggestedTopics from './useSuggestedTopics'
import { apiBaseUrl as derivedApiBaseUrl, helpLinkBaseUrl } from './targetEnvFunctions'
import { helpRuLinkBaseUrl } from './targetRuEnvFunctions'
import HelpOverlaySearch from './HelpOverlaySearch'
import HelpOverlayFooter from './HelpOverlayFooter'

const HelpOverlaySubnav = lazy(() => import('./HelpOverlaySubnav'))

const articleCss = css`
  padding: 0 16px;
`
const feedbackLinkWrapperCss = css`
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding: 0 8px;
`
const suggestedTopicListWrapperCss = css`
  padding: 8px;
`
const suggestedTopicListCss = css`
  display: grid;
  font-size: 14px;
  grid-row-gap: 16px;
  grid-template-columns: 1fr;
  margin: 8px 0;
`
const suggestedTopicExternalLinkCss = css`
  align-items: center;
  display: grid;
  grid-column-gap: 4px;
  grid-template-columns: auto auto;
  justify-content: start;
`
function helpTrayReducer(state, action) {
  const { type } = action
  switch (type) {
    case 'SHOW_SUGGESTED_TOPICS':
      return {
        ...state,
        showNavigationBar: false,
        showSuggestedTopics: true,
        showArticle: false,
      }
    case 'SHOW_ARTICLE_VIEW':
      return {
        ...state,
        showNavigationBar: true,
        showSuggestedTopics: false,
        showArticle: true,
      }
    default:
      return state
  }
}
const defaultState = {
  showNavigationBar: false,
  showSuggestedTopics: true,
  showArticle: false,
}

const helpTrayCache = new Cache({
  storeName: 'helpTrayCache',
  type: 'session',
})

export default function HelpOverlay({ helpActionUrl, apiBaseUrl = '', anchor, ...overlay }) {
  const [t] = useTranslation()
  const apiBaseUrlActual = apiBaseUrl || derivedApiBaseUrl
  const { isOpen, close, transitioning } = overlay
  const [authorized, requestStatus] = usePermission('CanAddPersonalDataPermission', 'FamilyTree')
  const { signedIn } = useUser()
  const canAddPersonalData = requestStatus === 'loaded' ? authorized : true
  const helpLinkUrl = signedIn && !canAddPersonalData ? helpRuLinkBaseUrl : helpLinkBaseUrl

  // When a tutorial has been used on a page, Help Overlay needs to be able to show a button
  // to open the tutorial again. This context provides info that's used to achieve this
  const tutorialContext = useContext(HelpTutorialContext)
  const [requestedUrl, setRequestedUrl] = useState(helpActionUrl)
  const [overrideUrl, setOverrideUrl] = useState(helpActionUrl)

  const [state, dispatch] = useReducer(helpTrayReducer, defaultState)
  const [currentArticleUrl, setCurrentArticleUrl] = useState('')

  const loadArticle = (url) => {
    setCurrentArticleUrl(url)
    if (url) {
      dispatch({ type: 'SHOW_ARTICLE_VIEW' })
    } else {
      dispatch({ type: 'SHOW_SUGGESTED_TOPICS' })
    }
    let relativeUrl = url
    if (!relativeUrl.startsWith('/')) {
      const indexOfHelp = url.indexOf('/help')
      if (indexOfHelp > -1) {
        relativeUrl = url.substring(indexOfHelp)
      }
    }
    helpTrayCache.setItem('articleUrl', relativeUrl)
  }

  useEffect(() => {
    if (helpActionUrl !== overrideUrl) {
      setOverrideUrl(helpActionUrl)
      setRequestedUrl(helpActionUrl)
    }
  }, [helpActionUrl, overrideUrl])
  useEffect(() => {
    if (isSupportedUrl(requestedUrl) && requestedUrl !== currentArticleUrl) {
      loadArticle(requestedUrl)
    }
    if (requestedUrl) {
      setRequestedUrl('')
    }
  }, [requestedUrl, currentArticleUrl])

  useEffect(() => {
    helpTrayCache.getItem('articleUrl').then((url) => {
      if (url) loadArticle(url)
    })
  }, [])

  const { suggestedTopicsList, suggestedTopicsError } = useSuggestedTopics({
    overrideUrl: helpActionUrl,
    apiBaseUrl: apiBaseUrlActual,
    isOpen,
  })

  const { articleHtml, isLoading: articleIsLoading } = useArticle(currentArticleUrl)

  if (!isOpen && !transitioning) return null
  return (
    <SupplementalOverlay
      overlayKey="helpOverlay"
      anchor={anchor}
      {...overlay}
      header={t('help', 'Help')}
      subHeader={
        <>
          <HelpOverlaySearch apiBaseUrlActual={apiBaseUrlActual} loadArticle={loadArticle} />{' '}
          {state.showNavigationBar && (
            <Suspense fallback="">
              <HelpOverlaySubnav loadArticle={loadArticle} currentArticleUrl={currentArticleUrl} />
            </Suspense>
          )}
        </>
      }
      footer={<HelpOverlayFooter />}
    >
      {/* CONTENTS - WILL BE DYNAMIC */}
      {state.showArticle && (
        <div className={articleCss}>
          <HelpArticle Content={articleIsLoading ? NoticeLoading : articleHtml} />
        </div>
      )}
      {state.showSuggestedTopics && (
        <>
          <List>
            {!tutorialContext.tutorialAvailable ? null : (
              <ListItem
                key="HELP_TUTORIAL"
                primaryText={t('help-tray.help-overview.heading', 'Overview')}
                secondaryText={tutorialContext.tutorialTitle}
                startElement={<ListItem.Icon Icon={HelpCompass} color={colors.gray00} background={colors.yellow30} />}
                data-testid="helpOverlayTutorialOpenButton"
                linkName="helpoverlay_tutorial_opened"
                onClick={() => {
                  tutorialContext.openTutorial()
                  close()
                }}
              />
            )}
            <ListItem
              key="GETTING_STARTED"
              overline={t('help-tray.getting-started.heading', 'Getting Started')}
              primaryText={t('help-tray.getting-started.subtitle', 'How to Do Family History')}
              startElement={<ListItem.Icon Icon={HelpTip} color={colors.gray00} background={colors.blue30} />}
              linkName="helpoverlay_gettingstarted"
              to={`${helpLinkUrl}/gettingstarted/`}
              data-testid="helpOverlayGettingStartedLink"
              external
            />
          </List>

          <Separator size="xs" />

          {suggestedTopicsError || !suggestedTopicsList?.length ? null : (
            <div className={suggestedTopicListWrapperCss}>
              <H3 size="H5" supplementary>
                {t('help-tray.suggested-topics.heading', 'Suggested Topics')}
              </H3>
              <div className={suggestedTopicListCss}>
                {suggestedTopicsList.map((topic) => {
                  const isSupported = isSupportedUrl(topic.url)
                  return isSupported ? (
                    <Link
                      key={topic.url}
                      to={topic.url}
                      onClick={(evt) => {
                        evt.preventDefault()
                        loadArticle(topic.url)
                      }}
                      linkName={`Suggested Topic Clicked (${topic.title})`}
                      data-testid="helpOverlaySuggestedTopicExternal"
                    >
                      <span>{topic.title}</span>
                    </Link>
                  ) : (
                    <Link
                      key={topic.url}
                      to={topic.url}
                      target="_blank"
                      linkName={`Suggested Topic Clicked (${topic.title})`}
                      data-testid="helpOverlaySuggestedTopicArticle"
                    >
                      <span className={suggestedTopicExternalLinkCss}>
                        {topic.title}
                        <MenuNewWindow size="xs" />
                      </span>
                    </Link>
                  )
                })}
              </div>
            </div>
          )}
        </>
      )}
      <div className={feedbackLinkWrapperCss}>
        <Divider />
        <Paragraph secondary size="xs">
          {t('help-tray.feedback.text', 'Is this helpful?')}{' '}
          <Link
            to="http://survey.usabilla.com/live/s/5f174a63203b124fc40ddc81"
            target="_blank"
            data-test="helpOverlayFeedbackLink"
            linkName="Help Overlay Feedback Link Clicked"
          >
            {t('help-tray.feedback.link', 'Give feedback.')}
          </Link>
        </Paragraph>
      </div>
    </SupplementalOverlay>
  )
}

HelpOverlay.propTypes = {
  /** An array of numbers indicating the [x, y] of where the help overlay should be initially positioned if a position isn't already in the cache. Optional, but if provided must be an array of two numbers */
  initialPosition(props) {
    // Return an error is an array is provided and it either doesn't have exactly two items,
    // or either item provided is not a number
    if (
      Array.isArray(props.initialPosition) &&
      (props.initialPosition.length !== 2 || props.initialPosition.some((n) => typeof n !== 'number'))
    ) {
      return new Error('The initialPosition prop for HelpOverlay must be an array of two numbers if provided')
    }
    return undefined
  },

  /**
   * The custom url signifying which set of custom suggested topics to request
   */
  helpActionUrl: PropTypes.string,
  close: PropTypes.func,
  isOpen: PropTypes.bool,
  isLoading: PropTypes.bool,
  transitioning: PropTypes.bool,
  handleTransitioned: PropTypes.func,

  /** This is to support sites that are part of FS, but not on the base URL, such as community.familysearch.org. This allows such use cases to specify which FS base URL their stie should use for fetching data. For any apps underneath the regular FS URLs, this prop should be omitted */
  apiBaseUrl: PropTypes.string,
}
